    "home.profileImgAlt": "Youssef Ahmed — Coaching personnel",
    "home.whatsappAskMessage": "Bonjour Youssef, j'aimerais en savoir plus sur vos programmes de coaching.",
    "dashboard.progressPhotoAlt": "Photo de progression",
    "profile.errors.notSignedIn": "Vous n'êtes pas connecté",
