    "home.profileImgAlt": "Youssef Ahmed — Personal Training",
    "home.whatsappAskMessage": "Ciao Youssef, vorrei avere informazioni sui tuoi programmi di allenamento.",
    "dashboard.progressPhotoAlt": "Foto di progresso",
    "profile.errors.notSignedIn": "Non hai effettuato l'accesso",
